// Tiled-streaming 1x1 conv2d, IC=64, OC=256, IH=IW=56, OH=OW=56, MP=4.
// channel_tile=32 -> IN_BEATS=2, OUT_BEATS=8 per pixel.
// Latency = IN_BEATS + OC_PASSES*(MP*K_TOTAL + 6) = 2 + 64*262 = 16770.
module node_conv_210 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);

    localparam IC            = 64;
    localparam OC            = 256;
    localparam IH            = 56;
    localparam IW            = 56;
    localparam OH            = 56;
    localparam OW            = 56;
    localparam KH            = 1;
    localparam KW            = 1;
    localparam K_TOTAL       = IC * KH * KW;
    localparam MP            = 4;
    localparam OC_PASSES     = (OC + MP - 1) / MP;
    localparam CHANNEL_TILE  = 32;
    localparam IN_BEATS      = (IC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam OUT_BEATS     = (OC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam TILE_BITS     = CHANNEL_TILE * 8;

    localparam SCALE_MULT    = 26902;
    localparam SCALE_SHIFT   = 21;

    localparam PROD_W        = 16;
    localparam ACC_W         = 32;
    localparam BIASED_W      = 33;
    localparam SCALE_CONST_W = 17;
    localparam SCALED_W      = 50;

    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};

    (* rom_style = "block", ram_style = "block" *)
    reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *)
    reg signed [31:0] biases  [0:OC-1];

    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_210_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_210_bias.hex", biases);
    end

    reg signed [7:0]            in_latch [0:IC-1];
    reg signed [ACC_W-1:0]      acc      [0:MP-1];
    reg signed [BIASED_W-1:0]   biased   [0:MP-1];
    reg signed [SCALED_W-1:0]   scaled   [0:MP-1];

    reg [1:0]  in_beat_idx;
    reg [5:0]  pixel_row;
    reg [5:0]  pixel_col;
    reg [11:0] active_emit_count;

    localparam ST_LOAD    = 3'd0;
    localparam ST_RUNNING = 3'd1;
    localparam ST_BIAS    = 3'd2;
    localparam ST_SCALE   = 3'd3;
    localparam ST_OUTPUT  = 3'd4;
    localparam ST_EMIT    = 3'd5;
    reg [2:0] state;

    reg [5:0] oc_group;
    reg [1:0] lane_counter;
    reg [6:0] k_counter;

    reg signed [7:0]        weight_q;
    reg signed [7:0]        in_val_q1;
    (* use_dsp = "yes" *)
    reg signed [PROD_W-1:0] mul_q;
    reg                     mac_valid_q1;
    reg                     mac_valid_q2;
    reg [1:0]               mac_lane_q1;
    reg [1:0]               mac_lane_q2;
    reg                     mac_done_issuing;
    reg [1:0]               drain_count;

    reg [OC*8-1:0]              out_pack;
    reg [3:0]                   out_beat_idx;
    reg signed [SCALED_W-1:0]   v_tmp;

    integer i;
    integer lane;
    integer global_oc;

    wire [13:0] w_addr;
    assign w_addr = (oc_group * MP + lane_counter) * K_TOTAL + k_counter;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state             <= ST_LOAD;
            ready_in          <= 1'b1;
            valid_out         <= 1'b0;
            data_out          <= {256{1'b0}};
            in_beat_idx       <= 2'd0;
            pixel_row         <= 6'd0;
            pixel_col         <= 6'd0;
            active_emit_count <= 12'd0;
            oc_group          <= 6'd0;
            lane_counter      <= 2'd0;
            k_counter         <= 7'd0;
            weight_q          <= 8'sd0;
            in_val_q1         <= 8'sd0;
            mul_q             <= {PROD_W{1'b0}};
            mac_valid_q1      <= 1'b0;
            mac_valid_q2      <= 1'b0;
            mac_lane_q1       <= 2'd0;
            mac_lane_q2       <= 2'd0;
            mac_done_issuing  <= 1'b0;
            drain_count       <= 2'd0;
            out_pack          <= {(OC*8){1'b0}};
            out_beat_idx      <= 4'd0;
            v_tmp             <= {SCALED_W{1'b0}};
        end else begin
            mac_valid_q1 <= 1'b0;
            mac_valid_q2 <= mac_valid_q1;
            mac_lane_q2  <= mac_lane_q1;
            mul_q        <= weight_q * in_val_q1;

            case (state)
                ST_LOAD: begin
                    if (valid_in && ready_in) begin
                        if (in_beat_idx == IN_BEATS - 1) begin
                            in_beat_idx      <= 2'd0;
                            ready_in         <= 1'b0; // [INVARIANT:READY_IN_GATING]
                            state            <= ST_RUNNING;
                            oc_group         <= 6'd0;
                            lane_counter     <= 2'd0;
                            k_counter        <= 7'd0;
                            mac_done_issuing <= 1'b0;
                            drain_count      <= 2'd0;
                        end else begin
                            in_beat_idx <= in_beat_idx + 2'd1;
                        end
                    end
                end

                ST_RUNNING: begin
                    if (!mac_done_issuing) begin
                        weight_q     <= weights[w_addr];
                        in_val_q1    <= in_latch[k_counter];
                        mac_valid_q1 <= 1'b1;
                        mac_lane_q1  <= lane_counter;
                        if (k_counter == K_TOTAL - 1) begin
                            k_counter <= 7'd0;
                            if (lane_counter == MP - 1) begin
                                lane_counter     <= 2'd0;
                                mac_done_issuing <= 1'b1;
                                drain_count      <= 2'd0;
                            end else begin
                                lane_counter <= lane_counter + 2'd1;
                            end
                        end else begin
                            k_counter <= k_counter + 7'd1;
                        end
                    end else begin
                        if (drain_count == 2'd2) begin
                            state            <= ST_BIAS;
                            mac_done_issuing <= 1'b0;
                        end else begin
                            drain_count <= drain_count + 2'd1;
                        end
                    end
                end

                ST_BIAS: begin
                    state <= ST_SCALE;
                end

                ST_SCALE: begin
                    state <= ST_OUTPUT;
                end

                ST_OUTPUT: begin
                    for (lane = 0; lane < MP; lane = lane + 1) begin
                        global_oc = oc_group * MP + lane;
                        v_tmp = (scaled[lane] +
                                 (scaled[lane][SCALED_W-1] ? SCALE_ROUND_HALF_M1
                                                           : SCALE_ROUND_HALF)
                                ) >>> SCALE_SHIFT; // [INVARIANT:ROUNDING]
                        out_pack[global_oc*8 +: 8] <= (v_tmp >  127) ?  8'sd127 :
                                                      (v_tmp < -128) ? -8'sd128 :
                                                                        v_tmp[7:0];
                    end
                    if (oc_group == OC_PASSES - 1) begin
                        valid_out    <= 1'b1; // [INVARIANT:VALID_OUT_LATENCY]
                        data_out     <= out_pack[0 +: TILE_BITS];
                        out_beat_idx <= 4'd0;
                        state        <= ST_EMIT;
                    end else begin
                        oc_group         <= oc_group + 6'd1;
                        lane_counter     <= 2'd0;
                        k_counter        <= 7'd0;
                        mac_done_issuing <= 1'b0;
                        drain_count      <= 2'd0;
                        state            <= ST_RUNNING;
                    end
                end

                ST_EMIT: begin
                    if (out_beat_idx == OUT_BEATS - 1) begin
                        valid_out    <= 1'b0;
                        ready_in     <= 1'b1; // [INVARIANT:READY_IN_GATING]
                        out_beat_idx <= 4'd0;
                        state        <= ST_LOAD;
                        if (active_emit_count == OH*OW - 1) begin
                            pixel_row         <= 6'd0;
                            pixel_col         <= 6'd0;
                            active_emit_count <= 12'd0;
                        end else if (pixel_col == OW - 1) begin
                            pixel_col         <= 6'd0;
                            pixel_row         <= pixel_row + 6'd1;
                            active_emit_count <= active_emit_count + 12'd1;
                        end else begin
                            pixel_col         <= pixel_col + 6'd1;
                            active_emit_count <= active_emit_count + 12'd1;
                        end
                    end else begin
                        out_beat_idx <= out_beat_idx + 4'd1;
                        data_out     <= out_pack[(out_beat_idx + 4'd1) * TILE_BITS +: TILE_BITS];
                        valid_out    <= 1'b1; // [INVARIANT:VALID_OUT_LATENCY]
                    end
                end

                default: state <= ST_LOAD;
            endcase
        end
    end

    always @(posedge clk) begin
        if (state == ST_LOAD && valid_in && ready_in) begin
            for (i = 0; i < CHANNEL_TILE; i = i + 1) begin
                in_latch[in_beat_idx*CHANNEL_TILE + i] <= data_in[i*8 +: 8];
            end
        end

        if (state == ST_LOAD && valid_in && ready_in && in_beat_idx == IN_BEATS - 1) begin
            for (i = 0; i < MP; i = i + 1) acc[i] <= {ACC_W{1'b0}};
        end else if (state == ST_OUTPUT && oc_group != OC_PASSES - 1) begin
            for (i = 0; i < MP; i = i + 1) acc[i] <= {ACC_W{1'b0}};
        end else if (mac_valid_q2) begin
            acc[mac_lane_q2] <= acc[mac_lane_q2] + mul_q;
        end

        if (state == ST_BIAS) begin
            for (lane = 0; lane < MP; lane = lane + 1) begin
                biased[lane] <= acc[lane] + biases[oc_group*MP + lane];
            end
        end

        if (state == ST_SCALE) begin
            for (lane = 0; lane < MP; lane = lane + 1) begin
                scaled[lane] <= $signed(biased[lane]) * $signed(SCALE_MULT_CONST);
            end
        end
    end

endmodule
